-- 360_buildout_m29.sql (GENERATED) — fill empty lessons for "ACC SRVY 1301 — Introduction to Surveying"
-- Module acc00001-0000-0000-0000-000000000001. Namespaced by tag 'buildout' / created_by 'buildout:m29' so pre-existing rows are untouched.
BEGIN;
DELETE FROM question_bank     WHERE module_id='acc00001-0000-0000-0000-000000000001' AND 'buildout' = ANY(tags);
DELETE FROM flashcards        WHERE module_id='acc00001-0000-0000-0000-000000000001' AND 'buildout' = ANY(tags);
DELETE FROM problem_templates WHERE module_id='acc00001-0000-0000-0000-000000000001' AND created_by='buildout:m29';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Surveying is the science and art of determining the relative positions of points on, above, or below the earth''s surface.','Major branches include geodetic, plane, boundary, topographic, construction, and control surveying.','Modern surveyors blend classical field skills with GNSS, total stations, and GIS.','Licensure as a Registered Professional Land Surveyor protects the public and is required to set boundaries.']::text[], learning_objectives=ARRAY['Define surveying and describe the major branches of the profession.','Summarize the history of surveying and its role in shaping civilization.','Identify the licensure path and professional responsibilities of a surveyor.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc01b01-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc01b01-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Surveyors use both the U.S. survey foot/international foot and metric units; know the conversions.','Significant figures communicate the precision of a measurement; do not report more than you measured.','Field notes are a permanent legal record: legible, in ink, never erased, with sketches and metadata.','1 acre = 43,560 sq ft; 1 mile = 5,280 ft; angles are in degrees-minutes-seconds (DMS).']::text[], learning_objectives=ARRAY['Convert among the units of length, area, and angle used in U.S. surveying.','Apply the rules of significant figures and rounding to measured quantities.','Record complete, legible, permanent field notes following accepted conventions.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc01b02-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc01b02-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['No measurement is exact; every observation contains error.','Mistakes are blunders; systematic errors follow physical laws and can be corrected; random errors remain.','The most probable value of repeated equal-weight observations is their mean.','Random errors propagate as the square root of the sum of squares.']::text[], learning_objectives=ARRAY['Distinguish mistakes, systematic errors, and random errors.','Compute the most probable value, residuals, and standard deviation of a set of observations.','Apply the laws of error propagation to combined quantities.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc01b03-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc01b03-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Elevation is vertical distance above a datum; leveling determines elevation differences.','A level establishes a horizontal line of sight; the rod measures vertical distance from it.','Differential leveling carries elevation from a benchmark to new points.','Balancing backsight and foresight distances cancels curvature, refraction, and collimation error.']::text[], learning_objectives=ARRAY['Explain the concepts of datum, elevation, and a level surface.','Identify the parts of a level and leveling rod and the types of leveling.','Describe sources of error in leveling and how to reduce them.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc01b04-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc01b04-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['HI = known elevation + backsight; new elevation = HI − foresight.','The arithmetic check: sum of backsights minus sum of foresights equals the net elevation change.','A turning point carries elevation forward between setups.','Loop misclosure should be small and is distributed among the setups.']::text[], learning_objectives=ARRAY['Compute height of instrument (HI) and elevations from backsight and foresight readings.','Keep and check a differential leveling field book using the arithmetic check.','Compute and adjust misclosure for a level loop.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc01b05-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc01b05-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Distances can be measured by pacing, taping, stadia, EDM, and GNSS, in increasing precision and cost.','Steel-tape measurements require corrections for temperature, tension, sag, and slope.','EDM measures distance from the travel time/phase of an electromagnetic signal.','Horizontal distance = slope distance × cos(vertical angle).']::text[], learning_objectives=ARRAY['Describe methods of distance measurement: pacing, taping, stadia, EDM, and GNSS.','Apply tape corrections for temperature, tension, sag, and slope.','Reduce a slope distance to a horizontal distance.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc01b06-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc01b06-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['An azimuth is a clockwise angle from north (0–360°); a bearing is an acute angle from north or south toward east or west.','Convert by identifying the quadrant of the line.','North can be true, magnetic, or grid; magnetic declination relates magnetic to true north.','Interior angles of a closed n-sided traverse sum to (n−2)×180°.']::text[], learning_objectives=ARRAY['Distinguish azimuths and bearings and convert between them.','Differentiate true, magnetic, and grid north and apply magnetic declination.','Compute interior, deflection, and angle-to-the-right relationships.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc01b07-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc01b07-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['The midterm integrates everything from Weeks 1–7.','Master HI leveling, tape/slope reduction, and azimuth–bearing conversion before proceeding.','Always carry units and apply the arithmetic/geometric checks.','Show your work: most credit is in the method, not just the final number.']::text[], learning_objectives=ARRAY['Review and consolidate Weeks 1–7: profession, units, errors, leveling, distance, and directions.','Solve integrated problems combining leveling, taping reduction, and direction conversion.','Self-assess readiness for the second half of the course.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc01b08-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc01b08-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['A total station combines an electronic theodolite, EDM, and onboard computer/data collector.','Setup requires precise centering over the point and leveling of the instrument.','Observing in both direct and reverse (face left/right) cancels many instrumental errors.','Repetition and meaning the angle improve precision.']::text[], learning_objectives=ARRAY['Identify the components and capabilities of a total station.','Describe proper setup: centering, leveling, and pointing.','Apply direct/reverse observation to remove instrumental errors.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc01b09-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc01b09-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['A traverse is a series of connected lines whose lengths and directions are measured.','Closed traverses provide checks; open traverses do not and are avoided for boundary work.','Angular misclosure = measured angle sum − theoretical (n−2)×180°.','Misclosure within tolerance is distributed before computing coordinates.']::text[], learning_objectives=ARRAY['Define a traverse and distinguish open, closed-loop, and closed-connecting traverses.','Describe field procedures for running a traverse with a total station.','Compute angular misclosure and assess whether a traverse meets specification.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc01b10-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc01b10-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=45, key_takeaways=ARRAY['Latitude = L cos(azimuth); departure = L sin(azimuth).','Closure: Σlatitudes and Σdepartures should be zero for a closed loop; their resultant is the linear misclosure.','Precision = linear misclosure ÷ traverse perimeter, expressed as 1:N.','The compass (Bowditch) rule distributes misclosure in proportion to leg length.']::text[], learning_objectives=ARRAY['Compute latitudes and departures of traverse legs from bearing/azimuth and length.','Determine linear misclosure and precision (relative accuracy).','Adjust a traverse with the compass (Bowditch) rule and compute final coordinates.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc01b11-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc01b11-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Coordinate geometry (COGO) connects coordinates, distances, and directions.','Inverse: distance = √(ΔE²+ΔN²); azimuth = atan2(ΔE, ΔN).','Forward: E = E₀ + L sin(Az); N = N₀ + L cos(Az).','COGO underlies stakeout, area, and intersection computations.']::text[], learning_objectives=ARRAY['Compute the inverse (distance and direction) between two coordinate points.','Compute a point''s coordinates from a known point, direction, and distance (forward).','Apply coordinate geometry to intersections and offsets.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc01b12-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc01b12-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['The shoelace formula gives parcel area directly from station coordinates.','Area = ½|Σ (xᵢ yᵢ₊₁ − xᵢ₊₁ yᵢ)|.','The DMD method computes area from latitudes and departures.','1 acre = 43,560 ft²; divide square feet by 43,560 to get acres.']::text[], learning_objectives=ARRAY['Compute the area of a parcel from coordinates using the shoelace (coordinate) method.','Compute area by the double-meridian-distance (DMD) method.','Convert areas among square feet, acres, and other units.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc01b13-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc01b13-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Topographic mapping locates planimetric features and elevations to portray the ground.','Contours are lines of equal elevation; they never cross and close on themselves.','A finished map needs scale, north arrow, legend, title block, and datum.','Digital terrain models (DTMs/TINs) now represent surfaces for design and volumes.']::text[], learning_objectives=ARRAY['Describe topographic surveys and methods of locating detail (radiation, GNSS, scanning).','Explain contours and their properties.','Identify the required elements of a survey map or plat.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc01b14-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc01b14-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['A boundary survey locates or re-establishes property lines from the best available evidence.','Monuments and the priority of calls govern where the line really is.','Descriptions are written as metes-and-bounds or lot-and-block (plat).','Texas land derives from sovereign grants and the GLO, not the federal PLSS.']::text[], learning_objectives=ARRAY['Describe the purpose of a boundary survey and the role of monuments and evidence.','Read metes-and-bounds and lot-and-block descriptions.','Explain the PLSS and how Texas land tenure differs.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc01b15-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc01b15-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['The final is comprehensive across all 15 instructional weeks.','Be fluent in leveling, traverse, COGO, and area computations end to end.','Always apply checks and report precision honestly.','Professional ethics and the duty to the public underlie every survey.']::text[], learning_objectives=ARRAY['Integrate the full course: measurement, computation, mapping, and boundary fundamentals.','Solve multi-step problems combining traverse, COGO, and area methods.','Demonstrate professional judgment about precision, checks, and ethics.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc01b16-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc01b16-0000-0000-0000-000000000001';
  'eeee2950-0000-0000-0000-000000000001', 'Length unit conversion: feet to acres frontage / chains', 'Length unit conversion: feet to acres frontage / chains', 'Introductory Surveying — Units', 'Unit conversion', 'numeric_input', 'easy', 'A parcel measures {{w}} ft by {{l}} ft. What is its area in acres?', 'round((w*l)/43560,3)', '{"decimals":3,"unit":"acres","tolerance":0.01}', '[{"name":"w","type":"integer","min":80,"max":400},{"name":"l","type":"integer","min":200,"max":700}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Area in square feet","formula":"w × l","calculation_template":"{{w}} × {{l}} ft²"},{"step_number":2,"title":"Convert to acres","result_template":"(area) ÷ 43,560 = {{_answer}} acres"}]'::jsonb, '{"method":"none"}'::jsonb, 'Multiply the sides to get square feet, then divide by 43,560 ft²/acre: ({{w}}×{{l}}) ÷ 43,560 = {{_answer}} acres.', 'acc00001-0000-0000-0000-000000000001', ARRAY['buildout','module-29','practice']::text[], true, 'buildout:m29');
  'eeee2950-0000-0000-0000-000000000002', 'Pythagorean / inverse distance between two coordinate points', 'Pythagorean / inverse distance between two coordinate points', 'Introductory Surveying — Coordinate Geometry', 'Inverse distance', 'numeric_input', 'medium', 'Point A is at ({{e1}} E, {{n1}} N) and point B is at ({{e2}} E, {{n2}} N). What is the horizontal distance from A to B (ft)?', 'round(hypot(de,dn),2)', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"e1","type":"integer","min":500,"max":1500},{"name":"n1","type":"integer","min":500,"max":1500},{"name":"de","type":"integer","min":50,"max":400},{"name":"dn","type":"integer","min":50,"max":400}]'::jsonb, '[{"name":"e2","formula":"e1+de"},{"name":"n2","formula":"n1+dn"}]'::jsonb, '[{"step_number":1,"title":"Coordinate differences","calculation_template":"ΔE = {{de}}, ΔN = {{dn}}"},{"step_number":2,"title":"Pythagorean distance","result_template":"√(ΔE²+ΔN²) = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Distance = √(ΔE² + ΔN²) = √({{de}}² + {{dn}}²) = {{_answer}} ft.', 'acc00001-0000-0000-0000-000000000001', ARRAY['buildout','module-29','practice']::text[], true, 'buildout:m29');
  'eeee2950-0000-0000-0000-000000000003', 'Azimuth to bearing conversion (SE / SW quadrants)', 'Azimuth to bearing conversion (SE / SW quadrants)', 'Introductory Surveying — Directions', 'Azimuth-bearing', 'numeric_input', 'medium', 'A line has an azimuth of {{az}}° (in the SW quadrant). What is the bearing angle (degrees, measured from south toward west)?', 'az-180', '{"decimals":0,"unit":"degrees","tolerance":0.5}', '[{"name":"az","type":"integer","min":190,"max":260}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Identify quadrant","calculation_template":"{{az}}° is between 180° and 270° → SW quadrant"},{"step_number":2,"title":"Bearing angle","result_template":"{{az}} − 180 = {{_answer}}°, i.e., S {{_answer}}° W"}]'::jsonb, '{"method":"none"}'::jsonb, 'For an azimuth in the SW quadrant (180°–270°), the bearing is S (Az−180)° W = S {{_answer}}° W.', 'acc00001-0000-0000-0000-000000000001', ARRAY['buildout','module-29','practice']::text[], true, 'buildout:m29');
  'eeee2950-0000-0000-0000-000000000004', 'Differential leveling: new elevation from HI and FS', 'Differential leveling: new elevation from HI and FS', 'Introductory Surveying — Leveling', 'HI / FS', 'numeric_input', 'easy', 'A backsight of {{bs}} ft is read on a benchmark at elevation {{bm}} ft. A foresight of {{fs}} ft is then read on a new point. What is the new point''s elevation (ft)?', 'round(bm+bs-fs,2)', '{"decimals":2,"unit":"ft","tolerance":0.005}', '[{"name":"bm","type":"float","min":100,"max":900,"decimals":2},{"name":"bs","type":"float","min":1,"max":9,"decimals":2},{"name":"fs","type":"float","min":1,"max":9,"decimals":2}]'::jsonb, '[{"name":"hi","formula":"bm+bs"}]'::jsonb, '[{"step_number":1,"title":"Height of instrument","formula":"HI = BM + BS","calculation_template":"{{bm:f2}} + {{bs:f2}} = {{hi:f2}} ft"},{"step_number":2,"title":"New elevation","result_template":"HI − FS = {{hi:f2}} − {{fs:f2}} = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'HI = {{bm:f2}} + {{bs:f2}} = {{hi:f2}} ft; new elevation = HI − FS = {{hi:f2}} − {{fs:f2}} = {{_answer}} ft.', 'acc00001-0000-0000-0000-000000000001', ARRAY['buildout','module-29','practice']::text[], true, 'buildout:m29');
COMMIT;
SELECT 'm29 ACC SRVY 1301 — Introduction to Surveying: ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='acc00001-0000-0000-0000-000000000001') || ' blocks.' AS status;