INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0001-0000-0000-000000000000', 'acc01b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What is surveying?</h3><p><strong>Surveying</strong> is the science, art, and technology of determining the relative positions of points on, above, or below the surface of the earth, and of representing those positions in usable form &mdash; as maps, plats, coordinates, or digital models. A surveyor answers three deceptively simple questions: <em>where is it, how big is it, and where is the boundary?</em></p><p>Surveying touches nearly every built thing. Before a road, pipeline, building, subdivision, or wind farm is constructed, a surveyor establishes control, defines property limits, and stakes the design onto the ground. After construction, surveyors verify that what was built matches what was designed (as-built surveys). The work demands precision, disciplined record-keeping, an understanding of law, and sound mathematics.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0001-0000-0000-000000000001', 'acc01b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Branches of surveying</h3><p>The profession spans several specialties that overlap in practice:</p><ul><li><strong>Geodetic surveying</strong> &mdash; large areas where the curvature of the earth must be accounted for.</li><li><strong>Plane surveying</strong> &mdash; smaller areas treated as flat; the basis of most local work.</li><li><strong>Boundary (cadastral) surveying</strong> &mdash; locating and re-establishing property lines and corners.</li><li><strong>Topographic surveying</strong> &mdash; mapping the natural and man-made features and elevations of the land.</li><li><strong>Construction (engineering) surveying</strong> &mdash; staking out designs and monitoring construction.</li><li><strong>Control surveying</strong> &mdash; establishing a precise network of horizontal and vertical reference points.</li></ul>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0001-0000-0000-000000000002', 'acc01b01-0000-0000-0000-000000000001', 'table', '{"headers":["Branch","Primary question","Typical product"],"rows":[["Boundary","Where is the property line?","Plat / boundary survey"],["Topographic","What is the shape of the ground?","Contour map / DTM"],["Construction","Where does the design go on the ground?","Stakes / layout report"],["Geodetic","Where is it on the earth?","Control network / coordinates"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0001-0000-0000-000000000003', 'acc01b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>A short history</h3><p>Surveying is one of the oldest applied sciences. Egyptian <em>rope-stretchers</em> re-established field boundaries after the annual Nile floods. The Romans built straight roads and aqueducts using the <em>groma</em> and <em>chorobates</em>. In the United States, surveying shaped the nation: George Washington, Thomas Jefferson, and Abraham Lincoln all worked as surveyors, and the <strong>Public Land Survey System (PLSS)</strong>, begun in 1785, divided the western territories into townships and sections. The instruments evolved from chains and transits to electronic distance measurement (EDM), total stations, and satellite positioning (GNSS), but the core mission &mdash; reliable measurement of position &mdash; has not changed.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0001-0000-0000-000000000004', 'acc01b01-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Texas is unusual: most of Texas was never part of the federal PLSS. Land originated as Spanish and Mexican grants and Republic/State of Texas grants administered by the General Land Office (GLO), producing metes-and-bounds descriptions rather than the rectangular section grid found in most other states."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0001-0000-0000-000000000005', 'acc01b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Becoming a surveyor</h3><p>Setting or re-establishing a property boundary is the practice of professional land surveying and is restricted by law to a licensed surveyor. In Texas, a <strong>Registered Professional Land Surveyor (RPLS)</strong> is licensed by the Texas Board of Professional Engineers and Land Surveyors (TBPELS). The typical path is education (degree or qualifying coursework), experience under a licensed surveyor, and examinations (the NCEES Fundamentals of Surveying, the Principles and Practice of Surveying, and a state-specific exam). Surveyors owe a duty to the public, must follow professional standards, and certify their work with a seal and signature.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0001-0000-0000-000000000006', 'acc01b01-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Evolution of surveying tools across history"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0001-0000-0000-000000000007', 'acc01b01-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Surveying determines relative positions and represents them as maps, coordinates, and plats.","Branches: geodetic, plane, boundary, topographic, construction, control.","The PLSS shaped most of the U.S.; Texas used grants and metes-and-bounds instead.","Boundary work requires a licensed surveyor (RPLS in Texas)."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0002-0000-0000-000000000000', 'acc01b02-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Units of measurement</h3><p>U.S. surveying uses a mix of customary and metric units. Length is commonly the <strong>foot</strong>, but be careful: the <em>U.S. survey foot</em> (1 m = 39.37 in exactly, so 1 ft = 1200/3937 m) differs from the <em>international foot</em> (1 ft = 0.3048 m exactly) by about 2 parts per million &mdash; trivial on a lot, but meaningful in State Plane Coordinates across a state. Older descriptions use the <strong>Gunter''s chain</strong> (66 ft, divided into 100 links) and the <strong>rod/pole/perch</strong> (16.5 ft). Angles are measured in <strong>degrees, minutes, and seconds (DMS)</strong>, where 1&deg; = 60&prime; and 1&prime; = 60&Prime;.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0002-0000-0000-000000000001', 'acc01b02-0000-0000-0000-000000000001', 'table', '{"headers":["Quantity","Equivalent"],"rows":[["1 foot","12 inches = 0.3048 m (intl)"],["1 Gunter''s chain","66 ft = 100 links = 4 rods"],["1 rod (pole/perch)","16.5 ft"],["1 mile","5,280 ft = 80 chains"],["1 acre","43,560 sq ft = 10 sq chains"],["1 degree","60 minutes = 3,600 seconds"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0002-0000-0000-000000000002', 'acc01b02-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Significant figures and rounding</h3><p><strong>Significant figures</strong> express how precisely a value is known. A distance recorded as 125.40 ft claims precision to a hundredth of a foot (5 significant figures); 125.4 ft claims only a tenth. The rules: (1) all non-zero digits are significant; (2) zeros between significant digits are significant; (3) trailing zeros after a decimal point are significant; (4) leading zeros are not. When you multiply or divide, the result carries no more significant figures than the least precise factor. When you add or subtract, round to the least precise decimal place. Round 5 to the even digit (round-half-to-even) to avoid systematic bias. Do not let a calculator''s eight displayed digits imply a precision you did not measure.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0002-0000-0000-000000000003', 'acc01b02-0000-0000-0000-000000000001', 'equation', '{"latex":"1\\ \\text{acre} = 43{,}560\\ \\text{ft}^2 = 10\\ \\text{chains}^2","label":"Acre definition","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0002-0000-0000-000000000004', 'acc01b02-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas legal descriptions and many older Texas surveys use the <strong>vara</strong> (a Spanish unit). The Texas vara is defined as 33&#8531; inches = 2.7&#773; ft (1 vara = 0.84667 m). Land grants in leagues and labors are based on the vara: 1 labor = 177.1 acres and 1 league = 4,428.4 acres. Always confirm which foot or vara a record uses before computing."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0002-0000-0000-000000000005', 'acc01b02-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Field notes</h3><p>Field notes are the surveyor''s original, permanent record and are admissible in court. Conventions ensure they remain trustworthy: write in <strong>permanent ink</strong> in a bound or rite-in-the-rain book; never erase &mdash; line out an error so the original remains visible; record the date, party, weather, instrument, and project; and include a neat <strong>sketch</strong> oriented with north up. Notes should be complete enough that someone else could reconstruct the survey. Even with data collectors, a field sketch and written notes capture context that raw coordinates cannot.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0002-0000-0000-000000000006', 'acc01b02-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Conventional field-note layout (data left, sketch right)"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0002-0000-0000-000000000007', 'acc01b02-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Know the foot variants, the chain, rod, and vara; 1 acre = 43,560 sq ft.","Significant figures must reflect actual measurement precision.","Field notes are permanent legal records: ink, no erasures, dated, with a sketch.","Texas records may use varas and league/labor land measures."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0003-0000-0000-000000000000', 'acc01b03-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Why measurements have error</h3><p>Every measurement is an estimate of a true value that can never be known exactly. The goal of error theory is not to eliminate error &mdash; that is impossible &mdash; but to <em>understand, bound, and minimize</em> it, and to report results with a defensible statement of their reliability. We separate three kinds of deviation from truth, and the surveyor''s discipline is to remove the first two so that only manageable random error remains.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0003-0000-0000-000000000001', 'acc01b03-0000-0000-0000-000000000001', 'table', '{"headers":["Type","Cause","Behavior","Remedy"],"rows":[["Mistake (blunder)","Carelessness: misread, transposed digits","Large, erratic","Procedure, checks, redundancy"],["Systematic error","Physical law: temperature, sag, instrument","Same sign, accumulates","Calibrate, model, correct"],["Random error","Limits of perception/instrument","Small, both signs","Repeat and average; statistics"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0003-0000-0000-000000000002', 'acc01b03-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Most probable value and precision</h3><p>For a set of <em>n</em> equally weighted observations, the <strong>most probable value</strong> is the arithmetic mean. The difference between each observation and the mean is its <strong>residual</strong>. The spread of the residuals is summarized by the <strong>standard deviation</strong>; a small standard deviation means the observations cluster tightly (high precision). Note the distinction between <em>precision</em> (repeatability) and <em>accuracy</em> (closeness to truth) &mdash; a consistently mis-calibrated tape can be very precise yet inaccurate.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0003-0000-0000-000000000003', 'acc01b03-0000-0000-0000-000000000001', 'equation', '{"latex":"\\sigma = \\sqrt{\\dfrac{\\sum v_i^{2}}{n-1}}","label":"Standard deviation of a sample (v = residual)","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0003-0000-0000-000000000004', 'acc01b03-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Error propagation</h3><p>When a quantity is computed from several measured values, the random errors of those values combine. For a sum or difference of independent quantities, the standard deviation of the result is the square root of the sum of the squares of the individual standard deviations. For example, if a traverse leg''s total length is the sum of several taped segments each with error &plusmn;0.01 ft, the total error grows only as &radic;n, not n. This <em>root-sum-square</em> behavior is why redundant measurements and averaging are so powerful: doubling the number of independent observations of one quantity reduces the standard error of the mean by &radic;2.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0003-0000-0000-000000000005', 'acc01b03-0000-0000-0000-000000000001', 'equation', '{"latex":"\\sigma_{\\text{sum}} = \\sqrt{\\sigma_1^{2} + \\sigma_2^{2} + \\cdots + \\sigma_n^{2}}","label":"Propagation for a sum of independent quantities","display":"block"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0003-0000-0000-000000000006', 'acc01b03-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Accuracy answers ''is it right?''; precision answers ''is it repeatable?''. A target hit tightly but off-center is precise but inaccurate; scattered shots centered on the bull''s-eye are accurate on average but imprecise."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0003-0000-0000-000000000007', 'acc01b03-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Three error types: mistakes, systematic, random.","Eliminate blunders with checks; correct systematic errors; treat random errors statistically.","Most probable value = mean; report precision via standard deviation.","Independent random errors propagate as root-sum-square."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0004-0000-0000-000000000000', 'acc01b04-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Datum, elevation, and level surfaces</h3><p><strong>Leveling</strong> is the process of determining the difference in <strong>elevation</strong> between points. Elevation is vertical distance measured from a reference <strong>datum</strong> &mdash; in the U.S. historically the National Geodetic Vertical Datum of 1929 (NGVD 29) and now the North American Vertical Datum of 1988 (NAVD 88). A <strong>level surface</strong> is one that is everywhere perpendicular to the direction of gravity (the plumb line); mean sea level approximates one such surface. A <strong>benchmark (BM)</strong> is a permanent point of known elevation from which other elevations are derived.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0004-0000-0000-000000000001', 'acc01b04-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Instruments</h3><p>The classic tool is the <strong>level</strong> &mdash; a telescope with cross-hairs whose line of sight is made horizontal by a spirit bubble or an internal compensator (an <em>automatic level</em>). The <strong>leveling rod</strong>, held vertically on a point, is read where the horizontal line of sight crosses it. A <strong>digital/bar-code level</strong> reads the rod electronically. Modern alternatives include the laser level and, for elevations referenced to a geoid model, GNSS. Key accessories: tripod, turning-point pin or plate, and a rod level (bull''s-eye bubble) to plumb the rod.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0004-0000-0000-000000000002', 'acc01b04-0000-0000-0000-000000000001', 'table', '{"headers":["Type of leveling","What it does"],"rows":[["Differential leveling","Carries elevation from a benchmark to other points via backsights/foresights"],["Profile leveling","Elevations along a line (e.g., a roadway centerline)"],["Trigonometric leveling","Elevation difference from a vertical angle and slope distance"],["Reciprocal leveling","Cancels curvature/refraction when crossing rivers/canyons"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0004-0000-0000-000000000003', 'acc01b04-0000-0000-0000-000000000001', 'equation', '{"latex":"\\Delta h \\approx \\dfrac{D^{2}}{2R}\\,(1-k)","label":"Combined curvature & refraction over distance D (k ≈ 0.13)","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0004-0000-0000-000000000004', 'acc01b04-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Balancing the distance from the instrument to the backsight rod and to the foresight rod makes curvature, refraction, and instrument collimation errors cancel between the two readings &mdash; the single most effective field technique in differential leveling."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0004-0000-0000-000000000005', 'acc01b04-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Sources of error</h3><p>Leveling errors include instrument <strong>collimation</strong> (line of sight not truly horizontal), <strong>earth curvature</strong> and atmospheric <strong>refraction</strong> (significant over long sights), a rod that is not plumb or not fully extended, settling of the instrument or turning point, and parallax. Good practice keeps sights short and balanced, uses stable turning points, runs a closed loop back to a known benchmark to obtain a <em>misclosure</em> check, and reads the rod to the nearest 0.01 ft (or mm). The misclosure is then distributed to the intermediate points.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0004-0000-0000-000000000006', 'acc01b04-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Differential leveling setup with balanced sights"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0004-0000-0000-000000000007', 'acc01b04-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Elevation is referenced to a vertical datum (NAVD 88 in modern U.S. work).","An automatic level provides a horizontal line of sight; the rod gives vertical distance.","Differential leveling transfers elevation from a benchmark to new points.","Balancing backsight and foresight lengths cancels curvature, refraction, and collimation."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0005-0000-0000-000000000000', 'acc01b05-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The HI method</h3><p>Differential leveling uses the <strong>height of instrument (HI)</strong> method. Set up the level between a point of known elevation and the next point. Read the rod on the known point &mdash; this <strong>backsight (BS)</strong> is added to the known elevation to obtain the HI, the elevation of the line of sight. Then read the rod on the next point &mdash; this <strong>foresight (FS)</strong> is subtracted from the HI to obtain that point''s elevation. Repeat, moving the instrument forward and using <strong>turning points (TP)</strong> to carry elevation across each setup.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0005-0000-0000-000000000001', 'acc01b05-0000-0000-0000-000000000001', 'equation', '{"latex":"HI = Elev_{BM} + BS \\qquad Elev_{new} = HI - FS","label":"Height-of-instrument leveling equations","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0005-0000-0000-000000000002', 'acc01b05-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Worked example</h3><p>Suppose BM-1 has elevation 500.00 ft. The backsight on BM-1 is 4.32 ft, so HI = 500.00 + 4.32 = 504.32 ft. The foresight to turning point TP-1 is 6.18 ft, so Elev(TP-1) = 504.32 &minus; 6.18 = 498.14 ft. Move the instrument forward, backsight TP-1 (say 5.05 ft) for a new HI of 503.19 ft, and continue. Every elevation is HI minus a foresight; every HI is an elevation plus a backsight.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0005-0000-0000-000000000003', 'acc01b05-0000-0000-0000-000000000001', 'table', '{"headers":["Station","BS (+)","HI","FS (−)","Elevation"],"rows":[["BM-1","4.32","504.32","","500.00"],["TP-1","5.05","503.19","6.18","498.14"],["BM-2","","","2.40","500.79"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0005-0000-0000-000000000004', 'acc01b05-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The arithmetic check and misclosure</h3><p>Before leaving the field, apply the <strong>arithmetic (page) check</strong>: the sum of all backsights minus the sum of all foresights must equal the net change in elevation (last elevation minus first). This catches addition errors. When the level run forms a <strong>loop</strong> back to the starting benchmark, the computed final elevation should equal the known starting value; any difference is the <strong>misclosure</strong>. Acceptable misclosure depends on the order of leveling (often expressed as a constant times the square root of the loop length in miles). The misclosure is distributed &mdash; typically in proportion to the number of setups or distance &mdash; to correct the intermediate elevations.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0005-0000-0000-000000000005', 'acc01b05-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Quick check: ΣBS − ΣFS = Elev(last) − Elev(first). If this is not satisfied, you have an arithmetic mistake in the notes, not a survey error."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0005-0000-0000-000000000006', 'acc01b05-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["HI = elevation + backsight; new elevation = HI − foresight.","Turning points carry elevation between instrument setups.","Arithmetic check: ΣBS − ΣFS = net elevation change.","Loop misclosure is computed against the known benchmark and distributed."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0006-0000-0000-000000000000', 'acc01b06-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Methods of measuring distance</h3><p>Surveyors choose a distance method by required precision: <strong>pacing</strong> (rough reconnaissance, ~1/50), <strong>odometer/measuring wheel</strong>, <strong>taping</strong> with a steel or fiberglass tape (~1/3,000 to 1/10,000 with corrections), <strong>stadia</strong> using a telescope''s stadia hairs and a rod (~1/300 to 1/500), <strong>electronic distance measurement (EDM)</strong>, and <strong>GNSS</strong>. Modern practice overwhelmingly uses EDM (in a total station) and GNSS, but understanding taping and its corrections explains where systematic error comes from and how legacy records were made.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0006-0000-0000-000000000001', 'acc01b06-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Tape corrections</h3><p>A steel tape is standardized at a specific temperature, tension, and support condition. Departures introduce <strong>systematic error</strong>: the tape lengthens when warmer and shortens when cooler (temperature); stretches under greater pull (tension); sags between supports, reading too long (sag); and a tape held along a slope measures more than the horizontal distance (slope). Each is corrected with a formula. Because these errors are systematic and same-signed, they accumulate over many tape lengths &mdash; the reason a precise tape survey is exacting work.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0006-0000-0000-000000000002', 'acc01b06-0000-0000-0000-000000000001', 'table', '{"headers":["Correction","Cause","Sign tendency"],"rows":[["Temperature","Tape warmer/cooler than standard","Long if warmer"],["Tension","Pull differs from standard","Long if over-pulled"],["Sag","Tape unsupported in the middle","Reads too long"],["Slope","Tape along incline, not horizontal","Reads too long"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0006-0000-0000-000000000003', 'acc01b06-0000-0000-0000-000000000001', 'equation', '{"latex":"H = S\\cos(\\alpha) = \\sqrt{S^{2}-\\Delta h^{2}}","label":"Horizontal distance from slope distance S and vertical angle α","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0006-0000-0000-000000000004', 'acc01b06-0000-0000-0000-000000000001', 'text', '{"html":"<h3>EDM and electronic measurement</h3><p><strong>EDM</strong> determines distance from the round-trip travel time (or phase shift) of an electromagnetic signal between the instrument and a reflector (prism) or, for reflectorless EDM, a surface. Modern total stations measure distances to a few millimeters plus a few parts per million. EDM eliminates the cumulative systematic errors of taping, though it still requires corrections for atmospheric conditions (temperature and pressure affect the speed of light) and for the prism constant. Distances are then reduced to horizontal and, for high-precision work, to a grid.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0006-0000-0000-000000000005', 'acc01b06-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Reduction order matters: an EDM gives a slope distance; reduce it to horizontal using the vertical angle or the elevation difference before using it in plane traverse computations."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0006-0000-0000-000000000006', 'acc01b06-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Reducing slope distance to horizontal distance"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0006-0000-0000-000000000007', 'acc01b06-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Method precision rises from pacing to taping to EDM/GNSS.","Tape corrections: temperature, tension, sag, slope — all systematic.","EDM uses signal travel time/phase; correct for atmosphere and prism constant.","Horizontal distance = slope distance × cos(vertical angle)."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0007-0000-0000-000000000000', 'acc01b07-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Directions: azimuth vs. bearing</h3><p>A line''s direction is expressed as an <strong>azimuth</strong> or a <strong>bearing</strong>. An <strong>azimuth</strong> is the clockwise angle from a reference meridian (usually north), ranging 0&deg; to 360&deg;. A <strong>bearing</strong> is the acute angle (0&deg; to 90&deg;) measured from north or south toward east or west, written as a quadrant direction such as N 42&deg;30&prime; E. Bearings are common in deeds and metes-and-bounds descriptions; azimuths are convenient for computation. Converting between them is a matter of identifying which quadrant the line falls in.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0007-0000-0000-000000000001', 'acc01b07-0000-0000-0000-000000000001', 'table', '{"headers":["Quadrant","Azimuth range","Bearing from azimuth (Az)"],"rows":[["NE","0°–90°","N (Az) E"],["SE","90°–180°","S (180−Az) E"],["SW","180°–270°","S (Az−180) W"],["NW","270°–360°","N (360−Az) W"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0007-0000-0000-000000000002', 'acc01b07-0000-0000-0000-000000000001', 'text', '{"html":"<h3>True, magnetic, and grid north</h3><p>There are three norths. <strong>True (geodetic) north</strong> points to the earth''s rotational pole. <strong>Magnetic north</strong> is where a compass needle points; it differs from true north by the <strong>magnetic declination</strong>, which varies by location and slowly with time. <strong>Grid north</strong> is the north of a map projection such as State Plane Coordinates; it differs from true north by the <em>convergence</em>. To convert a magnetic bearing to a true bearing, apply the declination (east declination is added to a magnetic azimuth to get true azimuth, with care for sign and direction).</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0007-0000-0000-000000000003', 'acc01b07-0000-0000-0000-000000000001', 'equation', '{"latex":"Az_{true} = Az_{magnetic} + \\delta \\quad (\\delta = \\text{declination, east }+)","label":"Magnetic-to-true azimuth","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0007-0000-0000-000000000004', 'acc01b07-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas-specific: re-tracing an old Texas deed often requires accounting for the magnetic declination at the time and place of the <em>original</em> survey, which can differ by several degrees from today''s declination. A bearing called ''N 45&deg; E'' in an 1870 grant is a magnetic bearing of that era, not a modern true bearing &mdash; rotate the entire call set to fit the found monuments."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0007-0000-0000-000000000005', 'acc01b07-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Angles in a traverse</h3><p>Field angles are measured several ways: <strong>interior angles</strong> (inside a closed polygon), <strong>angles to the right</strong> (clockwise from the backsight to the foresight, the total-station standard), and <strong>deflection angles</strong> (from the prolongation of the previous line, left or right, used on routes). A geometric check: the interior angles of a closed traverse with <em>n</em> sides should sum to (n&minus;2)&times;180&deg;. Any difference is the <em>angular misclosure</em>, distributed among the angles before computing directions.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0007-0000-0000-000000000006', 'acc01b07-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Azimuth and bearing relationships by quadrant"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0007-0000-0000-000000000007', 'acc01b07-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Azimuth: clockwise 0–360° from north; bearing: acute quadrant angle.","Convert by quadrant; deeds favor bearings, computation favors azimuths.","Three norths: true, magnetic, grid; declination relates magnetic to true.","Closed traverse interior angles sum to (n−2)×180°."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0008-0000-0000-000000000000', 'acc01b08-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What the midterm covers</h3><p>The Week 8 midterm assesses the first half of the course. Expect questions spanning the <strong>surveying profession and history</strong>, <strong>units and significant figures</strong>, <strong>theory of errors</strong>, <strong>leveling theory and field computations</strong>, <strong>distance measurement and reductions</strong>, and <strong>angles, azimuths, and bearings</strong>. Roughly half the points are computational, so practice the core formulas until they are automatic.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0008-0000-0000-000000000001', 'acc01b08-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Formulas you must know cold</h3><p>Going into the exam, you should be able to reproduce these from memory and know when each applies. Carry units throughout and apply checks: the arithmetic check in leveling and the (n&minus;2)&times;180&deg; angular check in traverse work catch most blunders before they cost you.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0008-0000-0000-000000000002', 'acc01b08-0000-0000-0000-000000000001', 'table', '{"headers":["Topic","Key relationship"],"rows":[["Leveling","HI = Elev + BS;  Elev = HI − FS"],["Leveling check","ΣBS − ΣFS = net Δ elevation"],["Slope reduction","H = S cosα"],["Area unit","1 acre = 43,560 ft²"],["Angles","Closed traverse Σ interior = (n−2)×180°"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0008-0000-0000-000000000003', 'acc01b08-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Exam tip: read every word of a word problem and sketch it. Most lost points come from misreading what is given (slope vs. horizontal distance, backsight vs. foresight, bearing vs. azimuth), not from arithmetic."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0008-0000-0000-000000000004', 'acc01b08-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Worked review problem</h3><p>A line has an azimuth of 230&deg;. Its bearing is S (230&minus;180) W = S 50&deg; W. A slope distance of 150.00 ft along it at a 4&deg; vertical angle reduces to a horizontal distance of 150.00 &times; cos 4&deg; = 149.63 ft. If that line begins at a point of elevation 612.40 ft and the far end is 10.45 ft lower, the far end is at 601.95 ft. Notice the problem braided together direction conversion, slope reduction, and elevation arithmetic &mdash; exactly the kind of integration the midterm rewards.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0008-0000-0000-000000000005', 'acc01b08-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Be fluent in HI leveling, slope reduction, and azimuth–bearing conversion.","Apply arithmetic and geometric checks to catch blunders.","Sketch word problems and confirm what is given.","Method earns most of the credit — show your steps."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0009-0000-0000-000000000000', 'acc01b09-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The total station</h3><p>A <strong>total station</strong> is the workhorse of modern field surveying. It integrates an <strong>electronic theodolite</strong> (measures horizontal and vertical angles), an <strong>EDM</strong> (measures distance), and an onboard <strong>computer/data collector</strong> that combines angle and distance into coordinates in real time. Robotic total stations add servo motors and a tracking link so one person can operate the instrument from the prism pole. Outputs include angles, distances, coordinates, and stakeout offsets, all logged digitally.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0009-0000-0000-000000000001', 'acc01b09-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Setting up</h3><p>A reliable observation starts with a correct setup. <strong>Centering</strong> places the instrument''s vertical axis exactly over the ground point using an optical or laser plummet. <strong>Leveling</strong> makes the vertical axis truly vertical using the foot screws and the plate (and circular) bubbles. These two steps interact &mdash; you alternate centering and leveling until both hold. A miscentered or unlevel instrument introduces errors that no amount of careful pointing will remove, so setup discipline is foundational.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0009-0000-0000-000000000002', 'acc01b09-0000-0000-0000-000000000001', 'table', '{"headers":["Instrument error","Effect","Removed by"],"rows":[["Collimation (horizontal)","Sight line not perpendicular to horizontal axis","Mean of direct & reverse"],["Horizontal-axis (trunnion) tilt","Axis not perpendicular to vertical axis","Mean of direct & reverse"],["Vertical-circle index","Vertical-angle zero offset","Mean of direct & reverse"],["Centering","Instrument off the point","Careful plummet setup"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0009-0000-0000-000000000003', 'acc01b09-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Direct and reverse observations</h3><p>The classic technique to remove instrumental error is to observe each angle in two positions of the telescope: <strong>direct (face left)</strong> and <strong>reverse (face right)</strong>, the telescope plunged 180&deg; between them. Averaging the two cancels collimation, horizontal-axis, and vertical-index errors because they reverse sign between faces. Observing several repetitions and taking the mean further reduces random pointing error. The spread of the repetitions is a built-in quality check; a large spread signals a setup or pointing problem.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0009-0000-0000-000000000004', 'acc01b09-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"''Face left'' and ''face right'' (or direct/reverse) refer to which side of the telescope the vertical circle is on. Always observe an important angle on both faces and mean them; this is the single most effective accuracy technique with a total station."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0009-0000-0000-000000000005', 'acc01b09-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Total-station components and setup over a point"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0009-0000-0000-000000000006', 'acc01b09-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["A total station = electronic theodolite + EDM + onboard computer.","Center over the point and level the instrument before observing.","Direct + reverse (face left/right) means cancel instrumental errors.","Repetition reduces random pointing error and provides a check."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0010-0000-0000-000000000000', 'acc01b10-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What is a traverse?</h3><p>A <strong>traverse</strong> is a framework of survey control: a series of connected lines (legs) whose lengths and directions are measured to determine the positions of the traverse stations. Traverses establish horizontal control for mapping, boundary, and construction surveys. There are three kinds: a <strong>closed-loop traverse</strong> returns to its starting point; a <strong>closed-connecting traverse</strong> begins and ends on different points of known coordinates; and an <strong>open traverse</strong> ends at an unknown point. Only the two closed forms provide a mathematical check, so boundary and control work uses closed traverses.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0010-0000-0000-000000000001', 'acc01b10-0000-0000-0000-000000000001', 'table', '{"headers":["Type","Starts/ends","Has a check?"],"rows":[["Closed loop","Returns to start","Yes"],["Closed connecting","Two known points","Yes"],["Open","Ends at unknown point","No (avoid)"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0010-0000-0000-000000000002', 'acc01b10-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Running a traverse</h3><p>In the field, occupy each station with the total station, backsight the previous station, and foresight the next, measuring the angle (usually <em>angle to the right</em>) and the distance to each. Procedures emphasize redundancy: observe angles direct and reverse, measure distances both ways where practical, and keep a clean station diagram. Establish or tie to at least one line of known direction (an azimuth from a control pair or from GNSS/astronomic observation) so the traverse can be oriented, and tie to known coordinates so it can be positioned.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0010-0000-0000-000000000003', 'acc01b10-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Angular misclosure</h3><p>The first check is angular. For a closed-loop traverse of <em>n</em> sides, the interior angles should sum to (n&minus;2)&times;180&deg;. The difference between the measured sum and this theoretical value is the <strong>angular misclosure</strong>. Specifications limit it &mdash; often a constant times &radic;n, where the constant reflects the instrument and order of work (for example, a few seconds to a minute per angle). If the misclosure is within tolerance, it is distributed (commonly equally) among the angles; if not, the field work must be checked or repeated before any coordinates are computed.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0010-0000-0000-000000000004', 'acc01b10-0000-0000-0000-000000000001', 'equation', '{"latex":"\\text{Angular misclosure} = \\left(\\textstyle\\sum \\text{measured angles}\\right) - (n-2)\\times 180^{\\circ}","label":"Angular misclosure of a closed-loop traverse","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0010-0000-0000-000000000005', 'acc01b10-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas boundary work: a traverse used to establish or retrace property corners must meet the positional-tolerance requirements of the Texas General Rules of Procedures and Practices (TBPELS) for the relevant category of survey. An open, uncheckable traverse is unacceptable for boundary determination."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0010-0000-0000-000000000006', 'acc01b10-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A closed-loop traverse with measured angles and distances"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0010-0000-0000-000000000007', 'acc01b10-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["A traverse measures connected lines to fix station positions.","Closed-loop and closed-connecting traverses self-check; open traverses do not.","Angular misclosure compares measured angle sum to (n−2)×180°.","Distribute misclosure only if it is within specification."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0011-0000-0000-000000000000', 'acc01b11-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Latitudes and departures</h3><p>After the angles are balanced and directions computed, each traverse leg is resolved into a north&ndash;south component, its <strong>latitude</strong>, and an east&ndash;west component, its <strong>departure</strong>. With azimuth measured clockwise from north, latitude = length &times; cos(azimuth) and departure = length &times; sin(azimuth). Northerly latitudes are positive, southerly negative; easterly departures positive, westerly negative. These components let us accumulate coordinates around the traverse and test its closure.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0011-0000-0000-000000000001', 'acc01b11-0000-0000-0000-000000000001', 'equation', '{"latex":"\\text{Lat} = L\\cos(Az), \\qquad \\text{Dep} = L\\sin(Az)","label":"Latitude and departure of a traverse leg","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0011-0000-0000-000000000002', 'acc01b11-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Linear misclosure and precision</h3><p>For a closed-loop traverse, you must return to your starting coordinates, so the sums of all latitudes and of all departures should each be zero. In practice small errors leave residuals: &sum;Lat and &sum;Dep are the <em>misclosure in latitude and departure</em>. Their resultant, the <strong>linear misclosure</strong>, is the straight-line distance the traverse fails to close. Dividing the perimeter by this misclosure gives the <strong>precision</strong> (relative accuracy), written as a ratio 1:N &mdash; for example, 1:12,000 means the misclosure is one part in twelve thousand of the distance traversed.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0011-0000-0000-000000000003', 'acc01b11-0000-0000-0000-000000000001', 'equation', '{"latex":"\\text{Linear misclosure} = \\sqrt{(\\textstyle\\sum \\text{Lat})^{2} + (\\sum \\text{Dep})^{2}}","label":"Linear misclosure","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0011-0000-0000-000000000004', 'acc01b11-0000-0000-0000-000000000001', 'equation', '{"latex":"\\text{Precision} = \\dfrac{\\text{perimeter}}{\\text{linear misclosure}} = 1{:}N","label":"Relative precision","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0011-0000-0000-000000000005', 'acc01b11-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The compass (Bowditch) rule</h3><p>If the precision meets specification, the misclosure is <strong>adjusted</strong> out. The most common method is the <strong>compass (Bowditch) rule</strong>, which assumes angles and distances are equally reliable and distributes the latitude/departure misclosure to each leg in proportion to that leg''s length relative to the perimeter. The correction to a leg''s latitude equals the total latitude misclosure times the leg length over the perimeter (and likewise for departure), applied with the sign that drives the sums toward zero. After adjustment, the latitudes and departures close exactly and are accumulated into final station coordinates.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0011-0000-0000-000000000006', 'acc01b11-0000-0000-0000-000000000001', 'table', '{"headers":["Step","Computation"],"rows":[["1. Components","Lat = L cos Az; Dep = L sin Az"],["2. Misclosure","ΣLat, ΣDep; resultant = √(ΣLat²+ΣDep²)"],["3. Precision","perimeter ÷ misclosure = 1:N"],["4. Adjust","Bowditch: correction ∝ leg length"],["5. Coordinates","Accumulate adjusted Lat/Dep"]]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0011-0000-0000-000000000007', 'acc01b11-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Compute precision before adjusting. Adjustment makes any traverse ''close'' perfectly on paper; only the pre-adjustment precision tells you whether the field work was good enough."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0011-0000-0000-000000000008', 'acc01b11-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Resolving legs into latitudes and departures"}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0011-0000-0000-000000000009', 'acc01b11-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Latitude = L cos(Az); departure = L sin(Az).","Linear misclosure is the resultant of ΣLat and ΣDep.","Precision = perimeter ÷ misclosure, stated as 1:N.","Bowditch rule distributes misclosure in proportion to leg length."]}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0012-0000-0000-000000000000', 'acc01b12-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Coordinates as the common language</h3><p>Modern surveying expresses position as plane <strong>coordinates</strong> &mdash; typically easting (E, the x-coordinate) and northing (N, the y-coordinate) in a State Plane or local system. <strong>Coordinate geometry</strong>, universally abbreviated <strong>COGO</strong>, is the toolkit that moves between coordinates, distances, and directions. Two operations do most of the work: the <em>inverse</em> (given two points, find the distance and direction between them) and the <em>forward</em> (given a point, a direction, and a distance, find the new point).</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0012-0000-0000-000000000001', 'acc01b12-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The inverse</h3><p>Given points 1 and 2, the differences are &Delta;E = E&#8322; &minus; E&#8321; and &Delta;N = N&#8322; &minus; N&#8321;. The horizontal <strong>distance</strong> is the hypotenuse, and the <strong>azimuth</strong> is found with the two-argument arctangent so the quadrant comes out correctly. Note the surveying convention: because azimuth is measured clockwise from north, the arctangent takes departure (&Delta;E) over latitude (&Delta;N) &mdash; that is, atan2(&Delta;E, &Delta;N).</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0012-0000-0000-000000000002', 'acc01b12-0000-0000-0000-000000000001', 'equation', '{"latex":"D = \\sqrt{(\\Delta E)^2+(\\Delta N)^2}, \\qquad Az = \\operatorname{atan2}(\\Delta E,\\ \\Delta N)","label":"Inverse: distance and azimuth between two points","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0012-0000-0000-000000000003', 'acc01b12-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The forward (radiation)</h3><p>The reverse operation computes new coordinates from a known point. Given a starting point (E&#8320;, N&#8320;), an azimuth Az, and a distance L, the new coordinates are E = E&#8320; + L&middot;sin(Az) and N = N&#8320; + L&middot;cos(Az). This is exactly the latitude/departure computation of a traverse leg, and it is how a total station radiates side shots, how stakeout points are generated, and how a metes-and-bounds description is converted into coordinates call by call.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0012-0000-0000-000000000004', 'acc01b12-0000-0000-0000-000000000001', 'equation', '{"latex":"E = E_0 + L\\sin(Az), \\qquad N = N_0 + L\\cos(Az)","label":"Forward computation of coordinates","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0012-0000-0000-000000000005', 'acc01b12-0000-0000-0000-000000000001', 'table', '{"headers":["Operation","Given","Find"],"rows":[["Inverse","Two points","Distance & azimuth between them"],["Forward","Point, azimuth, distance","New point''s coordinates"],["Intersection","Two lines (bearing/bearing, etc.)","Crossing point''s coordinates"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0012-0000-0000-000000000006', 'acc01b12-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Use atan2 (the two-argument arctangent), not a plain arctangent: atan2 returns the correct quadrant automatically, so you do not have to add 180° by hand for SW/NW lines."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0012-0000-0000-000000000007', 'acc01b12-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: The inverse between two coordinate points"}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0012-0000-0000-000000000008', 'acc01b12-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["COGO links coordinates, distances, and directions.","Inverse: D = √(ΔE²+ΔN²); Az = atan2(ΔE, ΔN).","Forward: E = E₀ + L sin(Az); N = N₀ + L cos(Az).","Forward computation drives radiation and stakeout."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0013-0000-0000-000000000000', 'acc01b13-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Why compute area?</h3><p>The <strong>area</strong> of a parcel is a fundamental survey deliverable &mdash; it appears in deeds, plats, tax records, and engineering quantities. Once a closed traverse around the parcel is measured and adjusted, the area follows directly from the coordinates of its corners. Two equivalent classical methods are taught: the <strong>coordinate (shoelace) method</strong> and the <strong>double-meridian-distance (DMD) method</strong>. Both assume a closed figure; an unbalanced traverse will give a wrong area, so closure and adjustment come first.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0013-0000-0000-000000000001', 'acc01b13-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The coordinate (shoelace) method</h3><p>The <strong>shoelace formula</strong> computes the area of any simple polygon from the coordinates of its vertices taken in order. Multiply each vertex''s x by the next vertex''s y, subtract the next vertex''s x times this vertex''s y, sum around the polygon, take the absolute value, and halve it. It is called the shoelace method because the cross-multiplications lace diagonally like a shoe. The result is exact for a polygon with straight sides and is the method built into virtually all COGO software.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0013-0000-0000-000000000002', 'acc01b13-0000-0000-0000-000000000001', 'equation', '{"latex":"A = \\tfrac{1}{2}\\left|\\sum_{i=1}^{n}(x_i\\,y_{i+1} - x_{i+1}\\,y_i)\\right|","label":"Shoelace (coordinate) area","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0013-0000-0000-000000000003', 'acc01b13-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The double-meridian-distance method</h3><p>The <strong>DMD method</strong> predates coordinates and works directly from latitudes and departures. The meridian distance of a line is the perpendicular distance from a reference meridian to the line''s midpoint; doubling it avoids fractions. The DMD of the first course equals its departure; each subsequent DMD equals the previous DMD plus the previous departure plus the current departure. The double area is the sum of (DMD &times; latitude) for every course; halving the absolute value gives the area. DMD and shoelace give identical results &mdash; DMD is essentially the shoelace formula reorganized around latitudes and departures.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0013-0000-0000-000000000004', 'acc01b13-0000-0000-0000-000000000001', 'table', '{"headers":["Area unit","Equivalent"],"rows":[["1 acre","43,560 ft²"],["1 acre","10 square chains"],["1 square mile","640 acres"],["1 hectare","10,000 m² ≈ 2.471 acres"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0013-0000-0000-000000000005', 'acc01b13-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"To convert: acres = square feet ÷ 43,560. A common sanity check — a square one chain (66 ft) on a side is 4,356 ft² = 0.1 acre."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0013-0000-0000-000000000006', 'acc01b13-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Shoelace area from vertex coordinates"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0013-0000-0000-000000000007', 'acc01b13-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Parcel area follows from corner coordinates once the traverse is closed.","Shoelace: A = ½|Σ(xᵢyᵢ₊₁ − xᵢ₊₁yᵢ)|.","DMD computes the same area from latitudes and departures.","Acres = square feet ÷ 43,560."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0014-0000-0000-000000000000', 'acc01b14-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Topographic mapping</h3><p>A <strong>topographic survey</strong> portrays the land: its <em>planimetric</em> features (roads, buildings, fences, streams) in plan position and its <em>relief</em> (elevations) via spot heights and contours. Detail is located by <strong>radiation</strong> from total-station control (each shot a forward computation), by <strong>RTK GNSS</strong>, by aerial or drone <strong>photogrammetry</strong>, and increasingly by <strong>LiDAR/laser scanning</strong> that captures dense point clouds. The product feeds map drafting and digital terrain models used for design.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0014-0000-0000-000000000001', 'acc01b14-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Contours</h3><p>A <strong>contour</strong> is a line connecting points of equal elevation. Contours obey consistent rules that make a map readable: every contour is a closed loop (within or beyond the map), contours never cross or split (except at a vertical cliff or overhang), closely spaced contours indicate steep ground while widely spaced contours indicate gentle slopes, and contours crossing a stream bend upstream into a ''V''. The vertical spacing between contours is the <strong>contour interval</strong>, chosen for the terrain and map scale.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0014-0000-0000-000000000002', 'acc01b14-0000-0000-0000-000000000001', 'table', '{"headers":["Contour rule","Meaning"],"rows":[["Equal elevation","Every point on one contour is at the same height"],["Close spacing","Steep slope"],["Wide spacing","Gentle slope"],["V points upstream","Contours cross streams bending uphill"],["Never cross","Two elevations cannot occupy one point (except a cliff)"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0014-0000-0000-000000000003', 'acc01b14-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Map elements and the plat</h3><p>A finished survey map or <strong>plat</strong> must communicate without ambiguity. Required elements typically include a <strong>title block</strong> (surveyor, client, date, project), a graphic and stated <strong>scale</strong>, a <strong>north arrow</strong> with the basis of bearings, a <strong>legend</strong> of symbols, the <strong>datum</strong> and coordinate system, monuments found and set, and the surveyor''s seal and certification. For a boundary plat, the bearings, distances, curve data, and area complete the legal picture. Today most maps originate in CAD/GIS, but the communication standards are unchanged.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0014-0000-0000-000000000004', 'acc01b14-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas: a subdivision <strong>plat</strong> recorded under Local Government Code Ch. 212 (municipal) or Ch. 232 (county) must meet statutory content and approval requirements and bear the RPLS seal. Mapping standards and the basis of bearings should follow the TBPELS General Rules and local platting ordinances."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0014-0000-0000-000000000005', 'acc01b14-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Elements of a finished topographic map"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0014-0000-0000-000000000006', 'acc01b14-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Topographic surveys capture features and elevations of the ground.","Contours connect equal elevations; spacing shows slope; V''s point upstream.","Finished maps need scale, north arrow, legend, title block, datum, and seal.","Texas plats follow LGC Ch. 212/232 and TBPELS rules."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0015-0000-0000-000000000000', 'acc01b15-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The boundary survey</h3><p>A <strong>boundary survey</strong> determines the location of the lines and corners of a parcel of land. Unlike a fresh measurement problem, boundary work is largely an <em>evidence</em> problem: the surveyor follows in the footsteps of the original surveyor, weighing monuments, records, occupation, and testimony to re-establish where the boundary was created. The surveyor does not create or move boundaries; they locate and report the boundary the law recognizes. This is why boundary determination is reserved to a licensed professional and why retracement skill defines the experienced surveyor.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0015-0000-0000-000000000001', 'acc01b15-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Evidence and the priority of calls</h3><p>When a deed''s elements conflict, the law ranks evidence by reliability &mdash; the <strong>priority (dignity) of calls</strong>. The general order is: <strong>natural monuments</strong> (a river, a marked tree) over <strong>artificial monuments</strong> (an iron pin, a set stone) over <strong>calls for adjoiners</strong> (a neighbor''s line) over <strong>courses and distances</strong> (bearings and lengths) over <strong>area</strong> (acreage). The logic is that the surveyor and parties were more certain of a physical object on the ground than of a number that could be mis-measured or mis-copied. Found, undisturbed original monuments usually control.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0015-0000-0000-000000000002', 'acc01b15-0000-0000-0000-000000000001', 'table', '{"headers":["Rank","Call type","Example"],"rows":[["1 (highest)","Natural monument","Centerline of a creek"],["2","Artificial monument","Found original iron rod"],["3","Adjoiner / line called for","''to the Smith line''"],["4","Course and distance","N 30° E, 210.00 ft"],["5 (lowest)","Area / quantity","''containing 5.00 acres''"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0015-0000-0000-000000000003', 'acc01b15-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Descriptions and the public lands</h3><p>Parcels are described two main ways. A <strong>metes-and-bounds</strong> description recites a sequence of courses (bearings and distances) and monuments around the perimeter from a point of beginning. A <strong>lot-and-block</strong> description refers to a recorded subdivision plat (''Lot 7, Block 3, Sunny Acres''). Across most of the U.S., the <strong>Public Land Survey System (PLSS)</strong> subdivides public land into 6-mile-square townships, each with 36 one-square-mile sections, described by township, range, and section. Texas, however, kept its public lands at independence and granted them itself, so Texas uses original surveys, leagues and labors, and metes-and-bounds rather than the PLSS grid.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0015-0000-0000-000000000004', 'acc01b15-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: Texas was never federal public domain after 1845 except for limited areas; land originated in Spanish/Mexican grants and Republic/State of Texas patents recorded at the General Land Office (GLO). Retracing a Texas boundary means working from GLO records and original-survey field notes, not PLSS township-and-range plats."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0015-0000-0000-000000000005', 'acc01b15-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A metes-and-bounds boundary with point of beginning and calls"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0015-0000-0000-000000000006', 'acc01b15-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Boundary surveying re-establishes existing lines from evidence, not new measurement alone.","Priority of calls: natural > artificial monuments > adjoiners > course/distance > area.","Descriptions are metes-and-bounds or lot-and-block (plat).","Texas land comes from sovereign grants and the GLO, not the federal PLSS."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0016-0000-0000-000000000000', 'acc01b16-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Scope of the final</h3><p>The comprehensive final exam covers the entire course. The computational core &mdash; <strong>leveling</strong>, <strong>distance reduction</strong>, <strong>directions</strong>, <strong>traverse closure and adjustment</strong>, <strong>coordinate geometry</strong>, and <strong>area</strong> &mdash; appears in multi-step problems, while conceptual questions test the <strong>profession, error theory, instruments, mapping, and boundary fundamentals</strong>. A typical capstone problem walks a small parcel from field observations through closure, adjustment, coordinates, and area, ending with the acreage for a plat.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0016-0000-0000-000000000001', 'acc01b16-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The end-to-end workflow</h3><p>Tie the course together as one pipeline. Observe angles and distances around a closed traverse; check and balance the angles against (n&minus;2)&times;180&deg;; compute directions; resolve each leg into latitudes and departures; test linear misclosure and precision; adjust by the compass rule; accumulate adjusted coordinates; and finally compute area by the shoelace method and convert to acres. Every stage has its own check &mdash; skipping the checks is how errors reach the final plat.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0016-0000-0000-000000000002', 'acc01b16-0000-0000-0000-000000000001', 'table', '{"headers":["Stage","Tool / check"],"rows":[["Field angles","Direct & reverse; (n−2)×180°"],["Directions","Azimuth/bearing conversion"],["Components","Lat = L cos Az; Dep = L sin Az"],["Closure","Misclosure & precision 1:N"],["Adjustment","Compass (Bowditch) rule"],["Area","Shoelace; ÷ 43,560 → acres"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0016-0000-0000-000000000003', 'acc01b16-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Ethics on the exam and in practice: a surveyor''s first duty is to the public. Never adjust field data to force a desired result, never certify work you did not supervise, and report precision and uncertainty honestly. A plat carries a seal because someone''s property rights depend on it."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0016-0000-0000-000000000004', 'acc01b16-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Final review problem</h3><p>A four-sided closed traverse has measured interior angles summing to 360&deg;02&prime; &mdash; an angular misclosure of +2&prime; over the theoretical (4&minus;2)&times;180&deg; = 360&deg;, distributed as &minus;0&prime;30&Prime; per angle. Its legs, resolved into latitudes and departures, leave &sum;Lat = +0.06 ft and &sum;Dep = &minus;0.08 ft, a linear misclosure of &radic;(0.06&sup2;+0.08&sup2;) = 0.10 ft. Over a 1,000-ft perimeter that is a precision of 1:10,000. After Bowditch adjustment the coordinates close, and the shoelace area comes to 53,500 ft&sup2; = 1.228 acres. That single problem exercises nearly the whole course.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2910-0016-0000-0000-000000000005', 'acc01b16-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["The final is comprehensive; expect integrated multi-step problems.","Know the traverse → coordinates → area pipeline cold.","Apply every check and report precision honestly.","Ethical duty to the public underlies the surveyor''s seal."]}'::jsonb, 5);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000001', 'Surveying', 'The science and art of determining the relative positions of points on, above, or below the earth''s surface and representing them in usable form.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000002', 'Plane surveying', 'Surveying of areas small enough that the curvature of the earth is neglected and the surface is treated as flat.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000003', 'PLSS', 'Public Land Survey System; the rectangular township-and-section subdivision of U.S. public lands begun in 1785.', 'Townships and sections', 'acc00001-0000-0000-0000-000000000001', 'acc01b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000004', 'RPLS', 'Registered Professional Land Surveyor; the Texas license required to practice land surveying.', 'Texas license', 'acc00001-0000-0000-0000-000000000001', 'acc01b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000005', 'Significant figures', 'The digits in a measurement that carry meaningful precision, including all certain digits plus one estimated digit.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000006', 'Gunter''s chain', 'An old length unit equal to 66 feet, divided into 100 links; 80 chains = 1 mile and 10 square chains = 1 acre.', '66 feet', 'acc00001-0000-0000-0000-000000000001', 'acc01b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000007', 'Vara', 'A Spanish unit of length used in Texas land grants; the Texas vara = 33&#8531; inches ≈ 2.78 ft.', 'Texas ≈ 2.78 ft', 'acc00001-0000-0000-0000-000000000001', 'acc01b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000008', 'DMS', 'Degrees, minutes, seconds: an angle format where 1° = 60′ and 1′ = 60″.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000009', 'Systematic error', 'An error that follows a physical law, has a consistent sign, and accumulates; it can be calibrated out or corrected mathematically.', 'Temperature, sag, instrument', 'acc00001-0000-0000-0000-000000000001', 'acc01b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000010', 'Random error', 'A small, unavoidable error of either sign caused by limits of perception and the instrument; reduced by repetition and statistics.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000011', 'Residual', 'The difference between an individual observation and the most probable value (mean) of the observations.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000012', 'Accuracy vs precision', 'Accuracy = closeness to the true value; precision = repeatability/closeness of repeated observations to each other.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000013', 'Benchmark (BM)', 'A permanent, monumented point of known elevation used as a reference for leveling.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000014', 'Datum', 'A reference surface or value from which elevations (or positions) are measured; e.g., NAVD 88 for elevation.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000015', 'Differential leveling', 'Determining elevation differences by reading a rod at backsight and foresight stations to carry elevation from a benchmark.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000016', 'Collimation error', 'Error caused when a level''s line of sight is not truly horizontal; reduced by balancing backsight and foresight distances.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000017', 'Height of instrument (HI)', 'The elevation of the level''s line of sight, equal to the known elevation plus the backsight reading.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000018', 'Backsight (BS)', 'A rod reading taken on a point of known elevation; added to that elevation to compute the HI.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000019', 'Foresight (FS)', 'A rod reading taken on a point of unknown elevation; subtracted from the HI to find that point''s elevation.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000020', 'Turning point (TP)', 'A temporary point on which both a foresight and a backsight are taken to carry elevation forward to a new instrument setup.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000021', 'EDM', 'Electronic distance measurement; determines distance from the travel time or phase shift of an electromagnetic signal to a reflector or surface.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000022', 'Stadia', 'An optical distance method using a telescope''s two stadia cross-hairs and a graduated rod; the rod interval times a stadia constant gives the distance.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000023', 'Pacing', 'Estimating distance by counting paces of a known average length; used for rough reconnaissance.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000024', 'Slope correction', 'Reduction of a measured slope distance to horizontal distance using the vertical angle or elevation difference.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000025', 'Azimuth', 'A horizontal direction measured clockwise from a reference meridian (usually north), from 0° to 360°.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000026', 'Bearing', 'A direction given as an acute angle (0–90°) measured from north or south toward east or west, e.g., S 31°15′ W.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000027', 'Magnetic declination', 'The angle between magnetic north and true north at a location; it varies geographically and over time.', 'Magnetic vs. true north', 'acc00001-0000-0000-0000-000000000001', 'acc01b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000028', 'Deflection angle', 'The angle a line makes with the prolongation of the preceding line, measured right or left; common on route surveys.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000029', 'Midterm scope', 'Weeks 1–7: profession/history, units & significant figures, error theory, leveling, distance measurement, and directions.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b08-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000030', 'Integrated problem', 'An exam item that combines several topics (e.g., reduce a slope distance, convert its azimuth to a bearing, then compute an elevation).', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b08-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000031', 'Method credit', 'Exam points awarded for the correct procedure and shown work, not only the final numeric answer.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b08-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000032', 'Total station', 'An instrument combining an electronic theodolite, EDM, and onboard computer to measure angles and distances and compute coordinates.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000033', 'Centering', 'Positioning the instrument''s vertical axis precisely over the ground point using an optical or laser plummet.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000034', 'Direct and reverse', 'Observing an angle with the telescope in both face-left and face-right positions and meaning them to cancel instrumental errors.', 'Face left / face right', 'acc00001-0000-0000-0000-000000000001', 'acc01b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000035', 'Robotic total station', 'A servo-driven total station that tracks the prism and can be operated remotely by one person from the rod.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000036', 'Traverse', 'A series of connected survey lines whose lengths and directions are measured to fix the positions of control stations.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000037', 'Closed-loop traverse', 'A traverse that begins and ends at the same point, providing both angular and linear closure checks.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000038', 'Open traverse', 'A traverse that ends at a point of unknown position and provides no closure check; unsuitable for boundary work.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000039', 'Angular misclosure', 'The difference between the measured sum of a closed traverse''s angles and the theoretical (n−2)×180°.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000040', 'Latitude (of a leg)', 'The north–south component of a traverse leg; latitude = length × cos(azimuth), positive north.', 'N–S component', 'acc00001-0000-0000-0000-000000000001', 'acc01b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000041', 'Departure (of a leg)', 'The east–west component of a traverse leg; departure = length × sin(azimuth), positive east.', 'E–W component', 'acc00001-0000-0000-0000-000000000001', 'acc01b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000042', 'Linear misclosure', 'The resultant distance √(ΣLat²+ΣDep²) by which a closed traverse fails to close.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000043', 'Compass (Bowditch) rule', 'A traverse adjustment that distributes latitude/departure misclosure to each leg in proportion to the leg''s length.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000044', 'COGO', 'Coordinate geometry; the set of computations relating coordinates, distances, and directions in surveying.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000045', 'Inverse computation', 'Given two points'' coordinates, finding the distance and azimuth between them.', 'Points → distance & direction', 'acc00001-0000-0000-0000-000000000001', 'acc01b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000046', 'Forward computation', 'Given a point, an azimuth, and a distance, finding the new point''s coordinates.', 'Direction & distance → point', 'acc00001-0000-0000-0000-000000000001', 'acc01b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000047', 'Easting and northing', 'Plane-coordinate components: easting is the x (east) value and northing is the y (north) value of a point.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000048', 'Shoelace formula', 'A method to compute a polygon''s area from its vertex coordinates: A = ½|Σ(xᵢyᵢ₊₁ − xᵢ₊₁yᵢ)|.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000049', 'Double meridian distance (DMD)', 'An area method using latitudes and departures; the double area is Σ(DMD × latitude).', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000050', 'Acre', 'A unit of area equal to 43,560 square feet (10 square Gunter''s chains).', '43,560 ft²', 'acc00001-0000-0000-0000-000000000001', 'acc01b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000051', 'Meridian distance', 'The perpendicular distance from a reference meridian to the midpoint of a traverse course.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000052', 'Topographic survey', 'A survey that locates planimetric features and elevations to portray the configuration of the ground.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000053', 'Contour', 'A line on a map connecting points of equal elevation.', 'Equal-elevation line', 'acc00001-0000-0000-0000-000000000001', 'acc01b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000054', 'Contour interval', 'The constant vertical distance in elevation between adjacent contour lines on a map.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000055', 'Plat', 'A recorded map of a survey or subdivision showing boundaries, dimensions, monuments, and the surveyor''s certification.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000056', 'Boundary survey', 'A survey to locate or re-establish the lines and corners of a parcel based on the best available evidence.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000057', 'Priority (dignity) of calls', 'The legal ranking of conflicting deed elements: natural monuments > artificial monuments > adjoiners > course and distance > area.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000058', 'Metes and bounds', 'A property description that recites bearings, distances, and monuments around the perimeter from a point of beginning.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000059', 'General Land Office (GLO)', 'The Texas agency that administers state land grants and archives original survey records; Texas land tenure derives from it rather than the federal PLSS.', 'Texas, not PLSS', 'acc00001-0000-0000-0000-000000000001', 'acc01b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000060', 'Comprehensive final', 'An exam covering the full course: measurement, computation, mapping, and boundary fundamentals integrated into multi-step problems.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b16-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000061', 'Survey workflow', 'The end-to-end pipeline: observe → balance angles → compute directions → latitudes/departures → closure/precision → adjust → coordinates → area.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b16-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2940-0000-0000-0000-000000000062', 'Surveyor''s duty to the public', 'The ethical principle that a surveyor''s primary obligation is to protect the public, requiring honest measurement, disclosure, and competent work.', NULL, 'acc00001-0000-0000-0000-000000000001', 'acc01b16-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-29']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000001', 'Which branch of surveying must account for the curvature of the earth over large areas?', 'multiple_choice', '["Plane surveying","Geodetic surveying","Construction surveying","Boundary surveying"]'::jsonb, 'Geodetic surveying', 'Geodetic surveying covers areas large enough that earth curvature affects the measurements. Plane surveying treats the surface as flat.', 'easy', 'acc00001-0000-0000-0000-000000000001', 'acc01b01-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000002', 'What credential is required in Texas to set or re-establish property boundaries?', 'multiple_choice', '["Professional Engineer (PE)","Registered Professional Land Surveyor (RPLS)","Certified GIS Professional","Notary Public"]'::jsonb, 'Registered Professional Land Surveyor (RPLS)', 'Boundary determination is the practice of land surveying, restricted to an RPLS licensed by TBPELS.', 'easy', 'acc00001-0000-0000-0000-000000000001', 'acc01b01-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000003', 'How many square feet are in one acre?', 'numeric_input', '[]'::jsonb, '43560', 'By definition, 1 acre = 43,560 square feet (10 square Gunter''s chains).', 'easy', 'acc00001-0000-0000-0000-000000000001', 'acc01b02-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000004', 'A distance is recorded as 84.30 ft. How many significant figures does this value carry?', 'multiple_choice', '["2","3","4","5"]'::jsonb, '4', 'Digits 8, 4, 3, and the trailing 0 after the decimal are all significant, giving 4 significant figures.', 'medium', 'acc00001-0000-0000-0000-000000000001', 'acc01b02-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000005', 'Errors that follow a physical law and accumulate with the same sign (such as tape thermal expansion) are called:', 'multiple_choice', '["Random errors","Systematic errors","Mistakes","Standard errors"]'::jsonb, 'Systematic errors', 'Systematic errors are predictable and can be calibrated or mathematically corrected.', 'easy', 'acc00001-0000-0000-0000-000000000001', 'acc01b03-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000006', 'Five equally weighted distance observations are 100.02, 100.05, 100.01, 100.04, 100.03 ft. What is the most probable value (ft)?', 'numeric_input', '[]'::jsonb, '100.03', 'The most probable value of equally weighted observations is the mean: (100.02+100.05+100.01+100.04+100.03)/5 = 100.03 ft.', 'medium', 'acc00001-0000-0000-0000-000000000001', 'acc01b03-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000007', 'Which field technique cancels curvature, refraction, and collimation error in differential leveling?', 'multiple_choice', '["Reading the rod to the nearest foot","Balancing backsight and foresight distances","Using a longer line of sight","Holding the rod at an angle"]'::jsonb, 'Balancing backsight and foresight distances', 'Equal backsight and foresight lengths cause these errors to cancel between the two rod readings.', 'medium', 'acc00001-0000-0000-0000-000000000001', 'acc01b04-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000008', 'A backsight of 5.20 ft is taken on a benchmark at elevation 410.00 ft. What is the height of instrument (HI)?', 'numeric_input', '[]'::jsonb, '415.20', 'HI = elevation + backsight = 410.00 + 5.20 = 415.20 ft.', 'easy', 'acc00001-0000-0000-0000-000000000001', 'acc01b05-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000009', 'With an HI of 415.20 ft, a foresight of 7.65 ft is read on a new point. What is that point''s elevation (ft)?', 'numeric_input', '[]'::jsonb, '407.55', 'Elevation = HI − FS = 415.20 − 7.65 = 407.55 ft.', 'easy', 'acc00001-0000-0000-0000-000000000001', 'acc01b05-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000010', 'A slope distance of 200.00 ft is measured at a vertical angle of 6°00′. What is the horizontal distance (ft)?', 'numeric_input', '[]'::jsonb, '198.90', 'H = S cosα = 200.00 × cos(6°) = 198.90 ft.', 'medium', 'acc00001-0000-0000-0000-000000000001', 'acc01b06-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000011', 'Which distance-measurement method is generally the LEAST precise?', 'multiple_choice', '["EDM","Steel taping with corrections","Pacing","GNSS"]'::jsonb, 'Pacing', 'Pacing is a rough reconnaissance method (~1/50), far less precise than taping, EDM, or GNSS.', 'easy', 'acc00001-0000-0000-0000-000000000001', 'acc01b06-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000012', 'Convert the azimuth 135°00′ to a quadrant bearing.', 'multiple_choice', '["N 45° E","S 45° E","S 45° W","N 45° W"]'::jsonb, 'S 45° E', '135° is in the SE quadrant; bearing = S (180−135) E = S 45° E.', 'medium', 'acc00001-0000-0000-0000-000000000001', 'acc01b07-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000013', 'The interior angles of a closed five-sided traverse should sum to how many degrees?', 'numeric_input', '[]'::jsonb, '540', '(n−2)×180° = (5−2)×180° = 540°.', 'medium', 'acc00001-0000-0000-0000-000000000001', 'acc01b07-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000014', 'A total station combines which three capabilities?', 'multiple_choice', '["Level, compass, and chain","Electronic theodolite, EDM, and onboard computer","GNSS receiver, barometer, and clinometer","Plane table, alidade, and stadia rod"]'::jsonb, 'Electronic theodolite, EDM, and onboard computer', 'A total station integrates angle measurement (theodolite), distance measurement (EDM), and computation/data collection.', 'easy', 'acc00001-0000-0000-0000-000000000001', 'acc01b09-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000015', 'Which traverse type provides NO mathematical check on the measurements?', 'multiple_choice', '["Closed-loop traverse","Closed-connecting traverse","Open traverse","Geodetic traverse"]'::jsonb, 'Open traverse', 'An open traverse ends at an unknown point, so there is no known value to check against.', 'easy', 'acc00001-0000-0000-0000-000000000001', 'acc01b10-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000016', 'A traverse leg is 300.00 ft long with an azimuth of 60°. What is its departure (ft)?', 'numeric_input', '[]'::jsonb, '259.81', 'Departure = L sin(Az) = 300.00 × sin 60° = 259.81 ft.', 'medium', 'acc00001-0000-0000-0000-000000000001', 'acc01b11-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000017', 'A closed traverse has a perimeter of 2,400 ft and a linear misclosure of 0.20 ft. What is the precision, expressed as 1:N?', 'multiple_choice', '["1:1,200","1:12,000","1:2,400","1:480"]'::jsonb, '1:12,000', 'Precision = perimeter ÷ misclosure = 2,400 ÷ 0.20 = 12,000, i.e., 1:12,000.', 'medium', 'acc00001-0000-0000-0000-000000000001', 'acc01b11-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000018', 'Point A is (1000.00 E, 1000.00 N) and point B is (1300.00 E, 1400.00 N). What is the distance A to B (ft)?', 'numeric_input', '[]'::jsonb, '500.00', 'D = √(ΔE²+ΔN²) = √(300²+400²) = √250000 = 500.00 ft.', 'medium', 'acc00001-0000-0000-0000-000000000001', 'acc01b12-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000019', 'A rectangular parcel measures 200.00 ft by 300.00 ft. What is its area in acres?', 'numeric_input', '[]'::jsonb, '1.377', 'Area = 200 × 300 = 60,000 ft²; ÷ 43,560 = 1.377 acres.', 'medium', 'acc00001-0000-0000-0000-000000000001', 'acc01b13-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000020', 'Closely spaced contour lines indicate:', 'multiple_choice', '["A gentle slope","A steep slope","Flat water","A property boundary"]'::jsonb, 'A steep slope', 'Where contours are close together, elevation changes rapidly over a short horizontal distance — steep ground.', 'easy', 'acc00001-0000-0000-0000-000000000001', 'acc01b14-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000021', 'In the priority of calls, which element generally controls over the others?', 'multiple_choice', '["Area (acreage stated)","Course and distance","A natural monument","The recited point of beginning"]'::jsonb, 'A natural monument', 'Natural monuments rank highest, then artificial monuments, adjoiners, course and distance, and finally area.', 'medium', 'acc00001-0000-0000-0000-000000000001', 'acc01b15-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2930-0000-0000-0000-000000000022', 'A surveyor''s primary ethical duty is to:', 'multiple_choice', '["The client who pays the fee","The public","Other surveyors","The equipment manufacturer"]'::jsonb, 'The public', 'Professional ethics place the surveyor''s first duty with the public, since property rights and safety depend on the work.', 'easy', 'acc00001-0000-0000-0000-000000000001', 'acc01b16-0000-0000-0000-000000000001', ARRAY['buildout','module-29']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
