INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2960-0000-0000-0000-000000000004', 'A backsight of {{bs}} ft is read on a benchmark at elevation {{bm}} ft. A foresight of {{fs}} ft is then read on a new point. What is the new point''s elevation (ft)?', 'numeric_input', '[]'::jsonb, '0', 'HI = {{bm:f2}} + {{bs:f2}} = {{hi:f2}} ft; new elevation = HI − FS = {{hi:f2}} − {{fs:f2}} = {{_answer}} ft.', 'easy', 'acc00001-0000-0000-0000-000000000001', NULL, ARRAY['buildout','module-29','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2950-0000-0000-0000-000000000004', 0.005);
